ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
	"correlationId": (correlationId default uuid()),
	"statusCode": vars.httpStatus,
	"statusMessage": (error.errorType.namespace ++ ":" ++ error.errorType.identifier),
	"description": if((error.errorType.namespace ++ ":" ++ error.errorType.identifier) contains "RETRY_EXHAUSTED")(error.description) else error.detailedDescription,
	"timestamp": (((now() >> "UTC")  as String {
		format : "yyyy/MM/dd HH:mm:ss"
	}) ++ " UTC"),
	notificationRequired: true
}

%dw 2.0
output text/plain
var explictHandlerCodes = [504,502]
---
"Correlation Id: " ++ (correlationId default uuid()) ++ "<br>" ++
  "Status Code: " ++ ((if ( explictHandlerCodes contains vars.httpStatus ) (vars.httpStatus) else (error.errorMessage.payload.errorCode default vars.httpStatus)) default 500) ++ "<br>" ++
  "Status Message: " ++ ((if ( explictHandlerCodes contains vars.httpStatus ) ((error.errorType.namespace ++ ":" ++ error.errorType.identifier)) else (error.errorMessage.payload.errorType)) default (error.errorType.namespace ++ ":" ++ error.errorType.identifier)) ++ "<br>" ++
  "Description: " ++ ((if ( explictHandlerCodes contains vars.httpStatus ) (if((error.errorType.namespace ++ ":" ++ error.errorType.identifier) contains "RETRY_EXHAUSTED")(error.description) else error.detailedDescription) else (error.errorMessage.payload.errorMessage)) default (if((error.errorType.namespace ++ ":" ++ error.errorType.identifier) contains "RETRY_EXHAUSTED")(error.description) else error.detailedDescription)) ++ "<br>" ++
  "Timestamp: " ++ ((if ( explictHandlerCodes contains vars.httpStatus ) (((now() >> "UTC")  as String {
		format : "yyyy/MM/dd HH:mm:ss"
	}) ++ " UTC") else (error.errorMessage.payload.errorDateTime)) default (((now() >> "UTC")  as String {
		format : "yyyy/MM/dd HH:mm:ss"
	}) ++ " UTC"))
